// Rotation des thèmes selon le jour de la semaine
const jour = new Date().getDay(); // 1=Lundi, 3=Mercredi, 5=Vendredi

const themes = {
  1: { // LUNDI — Véhicule
    categorie: 'vehicule',
    titre: 'Présentation véhicule',
    instruction: `Tu es community manager pour SHIP CARS, société de location de véhicules basée à Grenoble (38650 SINARD). 
Crée un post engageant qui met en avant la flotte SHIP CARS. Mentionne que les véhicules sont disponibles depuis Grenoble, parfaits pour explorer les Alpes, le Vercors ou la Chartreuse. Ton dynamique, accrocheur, avec emoji. Inclus un appel à l'action vers shipcars.fr.`
  },
  3: { // MERCREDI — Destination locale
    categorie: 'destination',
    titre: 'Destination & activité montagne',
    instruction: `Tu es community manager pour SHIP CARS, société de location de véhicules à Grenoble. 
Crée un post sur une destination incontournable autour de Grenoble UNIQUEMENT ACCESSIBLE EN VOITURE. Alterne entre ces idées : Les 2 Alpes (glacier l'été - ski sur neige en juillet!), Chamrousse, Alpe d'Huez, Col du Galibier, Lac de la Muzelle (depuis Vénosc), Plateau d'Emparis, Vercors (Gorges de la Bourne), Chartreuse (Grande Chartreuse), Lac du Monteynard, Col d'Ornon, Lac de Laffrey, Dévoluy, Col de la Croix de Fer. Insiste sur le fait qu'on ne peut y accéder qu'en voiture. Ton aventurier, inspirant. Inclus un appel à l'action vers shipcars.fr.`
  },
  5: { // VENDREDI — Promo / conseil
    categorie: 'promo_conseil',
    titre: 'Promo ou conseil pratique',
    instruction: `Tu es community manager pour SHIP CARS, société de location de véhicules à Grenoble. 
Crée alternativement soit : (1) une offre promotionnelle (week-end en montagne, tarif spécial été/ski, départ depuis la gare de Grenoble), soit (2) un conseil pratique de conduite en montagne (routes de cols, pneus hiver, que vérifier avant de partir en altitude). Ton utile et sympa. Inclus un appel à l'action vers shipcars.fr.`
  }
};

const theme = themes[jour] || themes[1];
const dateStr = new Date().toLocaleDateString('fr-FR');

return [{
  json: {
    ...theme,
    date: dateStr,
    jour: jour
  }
}];

