const response = $input.first().json;
const theme = $('🎯 Choisir le thème du jour').first().json;

// Extraire le texte de la réponse Claude
const rawContent = response.content[0].text;

// Parser le JSON retourné par Claude
let contenu;
try {
  // Chercher le JSON dans la réponse (Claude peut ajouter du texte autour)
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  contenu = JSON.parse(jsonMatch[0]);
} catch(e) {
  // Fallback si le parsing échoue
  contenu = {
    instagram: { texte: rawContent.substring(0, 500), hashtags: '#ShipCars #LocationVoiture #Grenoble #Alpes', conseil_visuel: 'Photo de voiture en montagne' },
    facebook: { texte: rawContent.substring(0, 800) },
    linkedin: { texte: rawContent.substring(0, 600) },
    tiktok: { script: rawContent.substring(0, 400), caption: 'Location voiture Grenoble 🚗', hashtags: '#ShipCars #Grenoble' },
    snapchat: { texte_court: 'Location voiture à Grenoble 🚗 shipcars.fr' }
  };
}

const date = theme.date;
const categorie = theme.categorie;

return [{
  json: {
    categorie,
    date,
    instagram: contenu.instagram,
    facebook: contenu.facebook,
    linkedin: contenu.linkedin,
    tiktok: contenu.tiktok,
    snapchat: contenu.snapchat
  }
}];

const date = new Date().toISOString();
console.log(`[SHIP CARS] Posts publiés le ${date}`);
return [{ json: { success: true, date, message: 'Posts publiés sur Facebook, Instagram, LinkedIn. Email envoyé pour TikTok/Snap.' } }];
